type AdditionalPermissionProfile struct {
	FileSystem Optional[AdditionalFileSystemPermissions] `json:"fileSystem,omitempty"`
	Network    Optional[AdditionalNetworkPermissions]    `json:"network,omitempty"`
}

func (v AdditionalPermissionProfile) MarshalJSON() ([]byte, error) {
	out := map[string]any{}
	if v.FileSystem.IsSet() {
		out["fileSystem"] = v.FileSystem
	}
	if v.Network.IsSet() {
		out["network"] = v.Network
	}
	return json.Marshal(out)
}

func (v *AdditionalPermissionProfile) UnmarshalJSON(data []byte) error {
	trimmed := bytes.TrimSpace(data)
	if bytes.Equal(trimmed, []byte("null")) {
		return DecodeError{Field: "", Reason: "cannot be null"}
	}
	var raw map[string]json.RawMessage
	if err := json.Unmarshal(trimmed, &raw); err != nil {
		return err
	}
	rawFileSystem, ok := raw["fileSystem"]
	if ok {
		if err := json.Unmarshal(rawFileSystem, &v.FileSystem); err != nil {
			return fmt.Errorf("field fileSystem: %w", err)
		}
	}
	rawNetwork, ok := raw["network"]
	if ok {
		if err := json.Unmarshal(rawNetwork, &v.Network); err != nil {
			return fmt.Errorf("field network: %w", err)
		}
	}
	return nil
}

